import React from 'react'
import LobbyPage from '../components/LobbyPage'
import { useLobby } from '../hooks/useLobby'
import type { GameState } from '../gameState'

type Props = {
  onContinue: (state: GameState, agents: any[]) => void
}

export default function LobbyContainer({ onContinue }: Props) {
  const { players, addPlayer, removePlayer, changeName, start, agents, toggleAgent } = useLobby()

  const handleStart = () => {
    const state = start()
    onContinue(state, agents)
  }

  return (
    <LobbyPage
      players={players}
      agents={agents}
      onAddPlayer={(name?: string) => addPlayer(name)}
      onRemovePlayer={removePlayer}
      onChangeName={changeName}
      onToggleAgent={toggleAgent}
      onStart={handleStart}
    />
  )
}

