import { useCallback, useEffect, useState } from 'react'
import type { Player, GameState } from '../gameState'
import { createPlayer, loadState, createStateFromNames, saveState } from '../gameState'
import type { Agent } from '../types/Agent'

/**
 * Lightweight hook to manage lobby player list, agents selection and starting a game.
 * Persists created game state and selected agents to localStorage via saveState.
 */
export function useLobby(initialNames: string[] = [], initialAgents: Agent[] = []) {
  const [players, setPlayers] = useState<Player[]>(() => {
    // Prefer restoring an existing saved game if present, otherwise use provided initial names
    const saved = loadState()
    if (saved && Array.isArray(saved.players) && saved.players.length > 0) return saved.players
    if (initialNames.length) return initialNames.map((n) => createPlayer(n))
    return []
  })

  const [agents, setAgents] = useState<Agent[]>(() => {
    // Use provided initialAgents or restore from saved state if present
    const saved = loadState()
    if (saved && (saved as any).agents && Array.isArray((saved as any).agents)) return (saved as any).agents
    return initialAgents
  })

  // Expose operations for the container/presentational component
  const addPlayer = useCallback((name = '') => {
    setPlayers((prev) => [...prev, createPlayer(name)])
  }, [])

  const removePlayer = useCallback((id: string) => {
    setPlayers((prev) => prev.filter((p) => p.id !== id))
  }, [])

  const changeName = useCallback((id: string, name: string) => {
    setPlayers((prev) => prev.map((p) => (p.id === id ? { ...p, name } : p)))
  }, [])

  const toggleAgent = useCallback((agent: Agent) => {
    setAgents((prev) => {
      const exists = prev.find((a) => a.uuid === agent.uuid)
      if (exists) return prev.filter((a) => a.uuid !== agent.uuid)
      return [...prev, agent]
    })
  }, [])

  const start = useCallback((maxRounds = 20): GameState => {
    const names = players.map((p) => (p.name && p.name.trim() ? p.name.trim() : 'Speler'))
    // createStateFromNames saves state before returning it; additionally persist agents
    const s = createStateFromNames(names, maxRounds)
    try {
      // store agents alongside saved state for convenience
      const raw = localStorage.getItem('pgpp-game-v1')
      if (raw) {
        const parsed = JSON.parse(raw)
        parsed.agents = agents
        localStorage.setItem('pgpp-game-v1', JSON.stringify(parsed))
      }
    } catch (e) {
      // ignore storage errors per conventions
      // eslint-disable-next-line no-console
      console.error('Failed to persist agents with game state', e)
    }
    return s
  }, [players, agents])

  // Optionally persist a lightweight lobby snapshot or perform side-effects here.
  useEffect(() => {
    // Intentionally empty for now; keep hook focused and side-effect free where possible.
  }, [players, agents])

  return { players, addPlayer, removePlayer, changeName, start, agents, toggleAgent, setAgents }
}
